commits.content:
@import 'tailwindcss';
@import 'tw-animate-css';

@custom-variant dark (&:is(.dark *));

:root {
  --background: oklch(0.09 0 0);
  --foreground: oklch(0.98 0 0);
  --card: oklch(0.18 0 0);
  --card-foreground: oklch(0.98 0 0);
  --popover: oklch(0.18 0 0);
  --popover-foreground: oklch(0.98 0 0);
  --primary: oklch(0.98 0 0);
  --primary-foreground: oklch(0.09 0 0);
  --secondary: oklch(0.30 0 0);
  --secondary-foreground: oklch(0.98 0 0);
  --muted: oklch(0.30 0 0);
  --muted-foreground: oklch(0.72 0 0);
  --accent: oklch(0.36 0 0);
  --accent-foreground: oklch(0.98 0 0);
  --destructive: oklch(0.577 0.245 27.325);
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.46 0 0);
  --input: oklch(0.34 0 0);
  --ring: oklch(0.68 0 0);
  --chart-1: oklch(0.7 0 0);
  --chart-2: oklch(0.6 0 0);
  --chart-3: oklch(0.5 0 0);
  --chart-4: oklch(0.4 0 0);
  --chart-5: oklch(0.3 0 0);
  --radius: 0.75rem;
  --sidebar: oklch(0.18 0 0);
  --sidebar-foreground: oklch(0.98 0 0);
  --sidebar-primary: oklch(0.98 0 0);
  --sidebar-primary-foreground: oklch(0.09 0 0);
  --sidebar-accent: oklch(0.30 0 0);
  --sidebar-accent-foreground: oklch(0.98 0 0);
  --sidebar-border: oklch(0.46 0 0);
  --sidebar-ring: oklch(0.68 0 0);
}

.light {
  --background: oklch(0.98 0 0);
  --foreground: oklch(0.15 0 0);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.15 0 0);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.15 0 0);
  --primary: oklch(0.15 0 0);
  --primary-foreground: oklch(0.98 0 0);
  --secondary: oklch(0.94 0 0);
  --secondary-foreground: oklch(0.15 0 0);
  --muted: oklch(0.94 0 0);
  --muted-foreground: oklch(0.45 0 0);
  --accent: oklch(0.94 0 0);
  --accent-foreground: oklch(0.15 0 0);
  --destructive: oklch(0.577 0.245 27.325);
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.88 0 0);
  --input: oklch(0.88 0 0);
  --ring: oklch(0.65 0 0);
  --chart-1: oklch(0.3 0 0);
  --chart-2: oklch(0.4 0 0);
  --chart-3: oklch(0.5 0 0);
  --chart-4: oklch(0.6 0 0);
  --chart-5: oklch(0.7 0 0);
  --sidebar: oklch(0.96 0 0);
  --sidebar-foreground: oklch(0.15 0 0);
  --sidebar-primary: oklch(0.15 0 0);
  --sidebar-primary-foreground: oklch(0.98 0 0);
  --sidebar-accent: oklch(0.94 0 0);
  --sidebar-accent-foreground: oklch(0.15 0 0);
  --sidebar-border: oklch(0.88 0 0);
  --sidebar-ring: oklch(0.65 0 0);
}

.dark {
  --background: oklch(0.09 0 0);
  --foreground: oklch(0.98 0 0);
  --card: oklch(0.18 0 0);
  --card-foreground: oklch(0.98 0 0);
  --popover: oklch(0.18 0 0);
  --popover-foreground: oklch(0.98 0 0);
  --primary: oklch(0.98 0 0);
  --primary-foreground: oklch(0.09 0 0);
  --secondary: oklch(0.30 0 0);
  --secondary-foreground: oklch(0.98 0 0);
  --muted: oklch(0.30 0 0);
  --muted-foreground: oklch(0.72 0 0);
  --accent: oklch(0.36 0 0);
  --accent-foreground: oklch(0.98 0 0);
  --destructive: oklch(0.396 0.141 25.723);
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.46 0 0);
  --input: oklch(0.34 0 0);
  --ring: oklch(0.68 0 0);
  --chart-1: oklch(0.7 0 0);
  --chart-2: oklch(0.6 0 0);
  --chart-3: oklch(0.5 0 0);
  --chart-4: oklch(0.4 0 0);
  --chart-5: oklch(0.3 0 0);
  --sidebar: oklch(0.18 0 0);
  --sidebar-foreground: oklch(0.98 0 0);
  --sidebar-primary: oklch(0.98 0 0);
  --sidebar-primary-foreground: oklch(0.09 0 0);
  --sidebar-accent: oklch(0.30 0 0);
  --sidebar-accent-foreground: oklch(0.98 0 0);
  --sidebar-border: oklch(0.46 0 0);
  --sidebar-ring: oklch(0.68 0 0);
}

@theme inline {
  --font-sans: 'Geist', 'Geist Fallback';
  --font-mono: 'Geist Mono', 'Geist Mono Fallback';
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
}

@layer base {
  * {
    @apply border-border outline-ring;
  }
  body {
    @apply bg-background text-foreground;
  }

  button:not(:disabled),
  a[href],
  select:not(:disabled),
  summary,
  label:has(input:not(:disabled)),
  input[type="button"]:not(:disabled),
  input[type="submit"]:not(:disabled),
  input[type="reset"]:not(:disabled),
  input[type="checkbox"]:not(:disabled),
  input[type="radio"]:not(:disabled),
  input[type="range"]:not(:disabled),
  [role="button"]:not([aria-disabled="true"]) {
    cursor: pointer;
  }

  button:disabled,
  select:disabled,
  textarea:disabled,
  input:disabled,
  [aria-disabled="true"] {
    cursor: not-allowed;
  }

  .dark .shadow-xs,
  .dark .shadow-sm,
  .dark .shadow-md,
  .dark .shadow-lg,
  .dark .shadow-xl,
  .dark .shadow-2xl {
    box-shadow:
      0 0 0 1px var(--border),
      0 14px 34px color-mix(in oklch, black 68%, transparent);
  }
}

/* Scrollbar hide utility */
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

/* blur effect */
.back-blur {
  &::before {
    content:"";
    display:block;
    position:absolute;
    top:0;
    background: linear-gradient(to bottom, rgba(255,255,255,1), rgba(255,255,255,0));
    filter: blur(5px);
  }
}

/* Hide Next.js Dev Overlay Indicator badge to prevent blocking UI headers */
nextjs-portal,
[data-nextjs-toast-wrapper],
[data-next-badge] {
  display: none !important;
}
